const aiResponse = items[0].json.text  || items[0].json.response  || items[0].json.message?.content  || (items[0].json.choices && items[0].json.choices[0]?.message?.content)  || '';let parsed;
try {
  const jsonMatch = aiResponse.match(/\{[\s\S]*\}/);
  parsed = JSON.parse(jsonMatch[0]);
} catch (e) {
  parsed = {
    decision: 'MANUAL_REVIEW',
    reasoning: 'AI response could not be parsed — forwarding for human review.',
    approved_amount: null,
    risk_flags: ['parse_error'],
    claimant_name: 'Unknown',
    claimant_email: '',
    claim_type: 'unknown',
    summary: aiResponse.substring(0, 200)
  };
}

parsed.claim_id = 'CLM-' + Date.now();
parsed.processed_at = new Date().toISOString();
parsed.email_message_id = $('New Claim Uploaded').item.json.id || '';

return [{ json: parsed }];

