// ✅ Mock AI — controlled by Workflow Config node
// Set mock_decision in Workflow Config: 'APPROVED' | 'REJECTED' | 'MANUAL_REVIEW'
const mockDecision = $('Workflow Config').item.json.mock_decision || 'APPROVED';

const response = {
  decision: mockDecision,
  reasoning: 'Claim is valid. Police report confirms fault of other party. Documentation is complete with repair estimate, medical records, and towing receipt. Amount is within policy limits.',
  approved_amount: mockDecision === 'APPROVED' ? 10405 : null,
  risk_flags: mockDecision === 'MANUAL_REVIEW' ? ['high_value', 'missing_witness'] : mockDecision === 'REJECTED' ? ['insufficient_documentation', 'coverage_mismatch'] : [],
  claimant_name: 'James A. Mitchell',
  claimant_email: 'user@example.com',
  claim_type: 'collision',
  summary: 'Collision claim — other driver ran red light, front-end damage, $10,405 total'
};

return [{ json: { text: JSON.stringify(response) } }];
